+                    .command("Status", "wa status")
+                    .command("Diagnostics", "wa doctor")
+                    .alternative("Check wa.toml policy settings for explicit allow rules."),
+            ),
+            Self::Io(_) => Some(
+                Remediation::new("Check filesystem permissions and paths, then retry.")
+                    .command("Diagnostics", "wa doctor")
